import{_ as e,o as a,c as l,a2 as o}from"./chunks/framework.Crpw6aS5.js";const q=JSON.parse('{"title":"承保纪律 Underwriting Discipline","description":"保险业的生命线：为何巴菲特将承保纪律视为伯克希尔的核心竞争力","frontmatter":{"title":"承保纪律 Underwriting Discipline","description":"保险业的生命线：为何巴菲特将承保纪律视为伯克希尔的核心竞争力"},"headers":[],"relativePath":"02_concepts/underwriting-discipline.md","filePath":"02_concepts/underwriting-discipline.md"}'),i={name:"02_concepts/underwriting-discipline.md"};function r(h,t,p,n,c,u){return a(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="承保纪律-underwriting-discipline" tabindex="-1">承保纪律 Underwriting Discipline <a class="header-anchor" href="#承保纪律-underwriting-discipline" aria-label="Permalink to &quot;承保纪律 Underwriting Discipline&quot;">​</a></h1><hr><h2 id="核心出处" tabindex="-1">核心出处 <a class="header-anchor" href="#核心出处" aria-label="Permalink to &quot;核心出处&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">重点内容</th></tr></thead><tbody><tr><td style="text-align:left;">**[[/01_letters/1986年/核心总结</td><td style="text-align:left;">1986年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2001年/核心总结</td><td style="text-align:left;">2001年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2004年/核心总结</td><td style="text-align:left;">2004年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2017年/核心总结</td><td style="text-align:left;">2017年]]**</td></tr></tbody></table><hr><h2 id="保险生意的本质" tabindex="-1">保险生意的本质 <a class="header-anchor" href="#保险生意的本质" aria-label="Permalink to &quot;保险生意的本质&quot;">​</a></h2><p>保险公司的商业模式看起来简单：收取保费，在未来某个不确定的时刻赔付。</p><p>但这个&quot;简单&quot;的生意里藏着一个残酷的真相——<strong>保险是最容易赔钱的行业之一</strong>。大多数保险公司失败，不是因为投资失误，而是因为在承保时犯下了定价错误。</p><blockquote><p>&quot;保险业务的核心纪律只有一条：在承担风险之前，确保你得到的保费足够覆盖未来的赔付和运营成本。如果你在这一条上妥协，你的末日迟早会来。&quot; <cite>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2001年致股东信</cite></p></blockquote><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>将这种纪律称为&quot;保险业唯一的游戏规则&quot;。违背这条规则，无论公司有多大、品牌有多响亮，最终都会被市场淘汰。</p><h2 id="费率充足性-承保纪律的第一要义" tabindex="-1">费率充足性：承保纪律的第一要义 <a class="header-anchor" href="#费率充足性-承保纪律的第一要义" aria-label="Permalink to &quot;费率充足性：承保纪律的第一要义&quot;">​</a></h2><p>费率充足性（Rate Adequacy）是承保纪律的核心。它意味着：每一份保单的价格，都必须足以覆盖该保单预期可能产生的所有成本。</p><p>这听起来理所当然，但在实际业务中，诱惑无处不在：</p><ul><li>竞争对手降价，你的保费显得&quot;太贵&quot;</li><li>保费规模是保险公司最重要的增长指标</li><li>股东和华尔街总是期望看到更高的保费收入</li><li>经济下行时，企业客户会压低保费预算</li></ul><p>面对这些压力，大多数保险公司会选择妥协——降价、减少核保审查、接受风险更高的业务。但<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>的答案是：<strong>绝不</strong>。</p><blockquote><p>&quot;当费率不足时，我们会毫不犹豫地收缩业务规模。一年、两年、五年不赚钱都可以，但绝对不能以亏损为代价换取市场份额。保费规模是保险公司最不值得追求的数字。&quot; <cite>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2004年致股东信</cite></p></blockquote><h2 id="伯克希尔的承保原则" tabindex="-1"><a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>的承保原则 <a class="header-anchor" href="#伯克希尔的承保原则" aria-label="Permalink to &quot;[[伯克希尔]]的承保原则&quot;">​</a></h2><p><a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>的保险业务遵循一套严格的承保原则：</p><h3 id="原则一-宁可不接-不接烂单" tabindex="-1">原则一：宁可不接，不接烂单 <a class="header-anchor" href="#原则一-宁可不接-不接烂单" aria-label="Permalink to &quot;原则一：宁可不接，不接烂单&quot;">​</a></h3><p>在保险行业，拒绝业务是一种能力。大多数保险公司的问题是：他们接了太多不该接的业务。</p><blockquote><p>&quot;GEICO能够在过去二十年里持续盈利，关键在于我们敢于对不划算的业务说不。有时候，最聪明的承保决定就是放下电话。&quot; <cite>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2003年致股东信</cite></p></blockquote><p>GEICO的座右铭是：&quot;做一个慷慨的保险公司，但只在费率合适的时候。&quot;这种理念让GEICO在同行大规模亏损时依然保持了盈利。</p><h3 id="原则二-避免-大灾难-风险" tabindex="-1">原则二：避免&quot;大灾难&quot;风险 <a class="header-anchor" href="#原则二-避免-大灾难-风险" aria-label="Permalink to &quot;原则二：避免&quot;大灾难&quot;风险&quot;">​</a></h3><p><a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>的保险业务刻意回避那些可能导致毁灭性损失的单一风险——例如核战争、地震、恐怖袭击等。</p><p>这并不是因为这些风险无法承保，而是因为一旦发生，损失可能远超任何保险公司所能承受的范围。</p><blockquote><p>&quot;我们会承接任何合理的风险，但有一条红线：我们永远不会承担那些一旦发生就会让我们破产的风险。保护<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>的偿付能力，比任何一笔保费都重要。&quot; <cite>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2002年致股东信</cite></p></blockquote><h3 id="原则三-长期视角" tabindex="-1">原则三：长期视角 <a class="header-anchor" href="#原则三-长期视角" aria-label="Permalink to &quot;原则三：长期视角&quot;">​</a></h3><p>保险业务的周期性极强。在&quot;软市场&quot;（供给过剩、费率偏低）时期，许多保险公司会因为担心失去客户而降价承保。<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>的做法截然不同。</p><blockquote><p>&quot;在费率普遍偏低的年份，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>的保费收入会下降。我们不会为了维持收入数字而去做赔钱的生意。我们等待，等到市场纠正——它总会纠正的。&quot; <cite>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2008年致股东信</cite></p></blockquote><p>这种耐心让<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>在市场底部时能够获得充足的资金，而不是被历史遗留的亏损保单拖垮。</p><h2 id="承保纪律与浮存金的关系" tabindex="-1">承保纪律与浮存金的关系 <a class="header-anchor" href="#承保纪律与浮存金的关系" aria-label="Permalink to &quot;承保纪律与浮存金的关系&quot;">​</a></h2><p>理解承保纪律的关键，在于理解它与浮存金之间的深层联系。</p><p>浮存金的前提是：你能够以低成本——甚至零成本——获取资金。但如果承保业务亏损，浮存金就会变成一种负担，而非优势。<strong>亏损的浮存金成本远高于任何融资方式。</strong></p><blockquote><p>&quot;很多人只看到<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>拥有巨额浮存金，却忽略了一个基本事实：这些浮存金之所以有价值，正是因为我们用纪律来管理它们。没有纪律的浮存金是毒药，不是良药。&quot; <cite>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2006年致股东信</cite></p></blockquote><p>这就是为什么<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>将承保纪律称为&quot;保险业务的生命线&quot;——它不仅决定了保险业务本身是否盈利，更决定了浮存金这条&quot;资本生命线&quot;是否畅通。</p><h2 id="阿吉特·杰恩-承保纪律的守护者" tabindex="-1">阿吉特·杰恩：承保纪律的守护者 <a class="header-anchor" href="#阿吉特·杰恩-承保纪律的守护者" aria-label="Permalink to &quot;阿吉特·杰恩：承保纪律的守护者&quot;">​</a></h2><p>说到<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>的承保纪律，不得不提阿吉特·杰恩（<a href="/04_people/阿吉特·贾恩.html">Ajit Jain</a>）。他是<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>再保险业务的灵魂人物，被<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>多次公开称赞。</p><blockquote><p>&quot;阿吉特是我们见过的最出色的保险人才。他对风险的判断力、对定价的敏感度，都是我见过的顶尖水平。他一个人创造的浮存金价值，可能超过了许多中型保险公司整个公司的价值。&quot; <cite>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2011年致股东信</cite></p></blockquote><p>阿吉特的核心能力在于：他能准确评估那些极其复杂、超大型风险的价值，并以合理的价格承保。这种能力稀缺到几乎无可替代——<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>曾表示，如果阿吉特决定退休，他会&quot;非常非常难过&quot;。</p><h2 id="承保纪律对投资者的启示" tabindex="-1">承保纪律对投资者的启示 <a class="header-anchor" href="#承保纪律对投资者的启示" aria-label="Permalink to &quot;承保纪律对投资者的启示&quot;">​</a></h2><p>承保纪律不仅对保险公司重要，对投资者同样有深刻的启示意义：</p><blockquote><p>&quot;当你评估一家保险公司时，首先要看它的承保纪律是否严格。一个在好年景承销大量不赚钱业务的保险公司，迟早会在坏年景里赔光所有利润。&quot; <cite>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2009年致股东信</cite></p></blockquote><p><a href="/04_people/查理·芒格.html">芒格</a>也补充道：</p><blockquote><p>&quot;保险行业里，愚蠢的定价决策会缓慢地积累，最终以灾难告终。真正优秀的保险公司知道，克制比扩张更难，也更重要。&quot; <cite>——<a href="/04_people/查理·芒格.html">查理·芒格</a>，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦年会</cite></p></blockquote><h2 id="结语" tabindex="-1">结语 <a class="header-anchor" href="#结语" aria-label="Permalink to &quot;结语&quot;">​</a></h2><p>承保纪律，是<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>保险帝国得以运转的底层逻辑。它看似简单——&quot;只做划算的生意&quot;——但在实际操作中，它需要对抗人性的贪婪、对抗业绩压力、对抗行业惯例。</p><p>正是这种纪律，让<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>的浮存金成为真正的&quot;免费资本&quot;，而非&quot;有毒资产&quot;。它是<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>投资帝国得以不断壮大的根基之一。</p><blockquote><p>&quot;我们不需要比别人更聪明，我们只需要在别人失去理智的时候保持理智。这就是<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>保险业务的全部秘密。&quot; <cite>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2007年致股东信</cite></p></blockquote><h2 id="相关主题" tabindex="-1">相关主题 <a class="header-anchor" href="#相关主题" aria-label="Permalink to &quot;相关主题&quot;">​</a></h2><ul><li><a href="./insurance-float.html">保险浮存金</a> — 承保纪律的结果：低成本甚至负成本的资本</li><li><a href="/search.html?q=[伯克希尔">[伯克希尔</a>的保险帝国](./insurance-empire) — 旗下保险公司的全景图</li><li><a href="./../core-principles/margin-of-safety.html">风险管理与安全边际</a> — 承保纪律背后的风险管理哲学</li><li><a href="./../investment-philosophy/patience.html">耐心与理性</a> — 抵制诱惑，保持理智</li></ul>',50)])])}const d=e(i,[["render",r]]);export{q as __pageData,d as default};
